## Budget Control

Set spending limits to control API costs during agent execution.

```typescript
import { query } from "@anthropic-ai/claude-agent-sdk";

// Set a budget limit for the query
const response = query({
  prompt: "Perform comprehensive code analysis across the entire repository",
  options: {
    model: "claude-sonnet-4-5",
    workingDirectory: "/path/to/project",
    maxBudgetUsd: 2.5  // Stop execution if cost exceeds $2.50
  }
});

for await (const message of response) {
  if (message.type === 'error' && message.error?.type === 'budget_exceeded') {
    console.error('Budget limit exceeded:', message.error.message);
    break;
  } else if (message.type === 'assistant') {
    console.log(message.content);
  }
}

// Budget tracking for long-running agents
async function runBudgetedAgent() {
  const budgetLimit = 10.0;  // $10 budget
  let totalSpent = 0;

  const response = query({
    prompt: "Analyze security, performance, and test coverage across the codebase",
    options: {
      model: "claude-sonnet-4-5",
      maxBudgetUsd: budgetLimit
    }
  });

  try {
    for await (const message of response) {
      // Track spending and handle budget exhaustion
      if (message.type === 'system' && message.cost) {
        totalSpent += message.cost;
        console.log(`Current spending: $${totalSpent.toFixed(4)} / $${budgetLimit}`);
      }
    }
  } catch (error) {
    if (error.code === 'BUDGET_EXCEEDED') {
      console.log(`Agent stopped: Budget of $${budgetLimit} exceeded`);
    }
  }
}
```

## Plugins Integration

Extend agent capabilities with custom plugins for additional functionality.

```typescript
import { query } from "@anthropic-ai/claude-agent-sdk";

// Define custom plugins
const customPlugins = [
  {
    name: "analytics-tracker",
    version: "1.0.0",
    initialize: async (context) => {
      console.log("Analytics plugin initialized");
      // Setup tracking, logging, or monitoring
    },
    onToolCall: async (toolName, input) => {
      // Track tool usage
      analytics.track("tool_call", { tool: toolName });
    },
    onMessage: async (message) => {
      // Process messages
      if (message.type === 'assistant') {
        analytics.track("assistant_message", { length: message.content.length });
      }
    }
  },
  {
    name: "rate-limiter",
    version: "1.0.0",
    initialize: async (context) => {
      context.callCount = 0;
      context.lastReset = Date.now();
    },
    onToolCall: async (toolName, input, context) => {
      // Implement rate limiting logic
      context.callCount++;
      if (context.callCount > 100) {
        throw new Error("Rate limit exceeded: too many tool calls");
      }
    }
  }
];

const response = query({
  prompt: "Perform automated code review",
  options: {
    model: "claude-sonnet-4-5",
    plugins: customPlugins,
    workingDirectory: "/path/to/project"
  }
});

for await (const message of response) {
  console.log(message);
}
```

## Filesystem Settings Configuration

Control which filesystem settings are loaded by the SDK.

```typescript
import { query } from "@anthropic-ai/claude-agent-sdk";

// Load settings from all sources (user, project, local)
const allSettings = query({
  prompt: "Build a new feature with project conventions",
  options: {
    settingSources: ["user", "project", "local"],
    model: "claude-sonnet-4-5"
  }
});

// Load only project settings (useful for CI/CD)
const projectOnly = query({
  prompt: "Run automated code review",
  options: {
    settingSources: ["project"],
    model: "claude-sonnet-4-5"
  }
});

// No filesystem settings (fully isolated)
const isolated = query({
  prompt: "Analyze this code snippet",
  options: {
    settingSources: [],  // Don't load any settings files
    workingDirectory: "/tmp/sandbox",
    model: "claude-sonnet-4-5"
  }
});

// Combine with programmatic configuration
const hybrid = query({
  prompt: "Implement the user authentication system",
  options: {
    settingSources: ["project"],  // Load CLAUDE.md and settings.json
    systemPrompt: "Follow security best practices and company coding standards.",
